INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Managed Passkey Sign-Up and Sign-In$q$, $q$Corbado Connect ships ready-made SDKs and UI components so engineering teams can add WebAuthn-based passkey registration and login without building the cryptographic ceremony flows from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Authentication Process Mining$q$, $q$Corbado Observe traces every step of an authentication attempt to reveal where users abandon or fail passkey login, broken down by device, browser, and platform authenticator.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Per-User Debugging$q$, $q$Support and engineering teams can inspect individual authentication sessions to diagnose why a specific user's passkey attempt failed.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Rollout Controls and Safe Fallbacks$q$, $q$Passkey rollouts can be staged gradually across a user base, with automatic fallback to existing login methods when a device doesn't support passkeys.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Zero-PII Telemetry$q$, $q$Analytics are designed to surface conversion and failure data without capturing personally identifiable end-user information.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Identity Provider Integrations$q$, $q$Native integration with major IDPs including Okta, Auth0, Ping Identity, and Amazon Cognito, so Corbado layers onto an existing auth stack rather than replacing it.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$AI Assistant for Authentication Questions$q$, $q$An AI assistant is built into the platform to help teams interpret authentication data and troubleshoot passkey issues.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Enterprise Onboarding Support$q$, $q$Corbado provides implementation guidance for large-scale, phased passkey rollouts across millions of end users.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Purpose-built exclusively for passkeys, giving deeper funnel and device-level analytics than passkey features bolted onto general CIAM platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Works alongside an existing identity provider instead of requiring a full authentication migration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Zero-PII telemetry design addresses privacy concerns common with authentication analytics$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Corporate-backed (via PB Holding GmbH) rather than dependent on venture funding cycles, suggesting a stable, long-term-oriented company$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$No public, self-serve pricing — all plans require a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Small team (~10 people) relative to established CIAM vendors like Okta or Auth0$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Narrow focus on passkeys means it doesn't cover broader identity management needs like MFA policy engines or full user directories$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Two separate products (Connect vs. Observe) require buyers to first determine which model fits their existing stack$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$What is Corbado?$q$, $q$Corbado is a passkey intelligence and managed-authentication platform that helps enterprises deploy and analyze passwordless, WebAuthn-based login.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Is Corbado a replacement for my identity provider?$q$, $q$No. Corbado is designed to work alongside existing identity providers such as Okta, Auth0, and Amazon Cognito rather than replace them.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$What's the difference between Corbado Connect and Corbado Observe?$q$, $q$Corbado Connect is a managed passkey product with SDKs and UI components for teams that haven't built passkeys yet. Corbado Observe is an analytics and debugging layer for teams that already have a passkey implementation and want visibility into its performance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Does Corbado offer a free plan?$q$, $q$Corbado does not publish a free self-serve tier; pricing for both products is custom and quoted through a sales process.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Does Corbado collect personal user data in its analytics?$q$, $q$Corbado markets a zero-PII telemetry model, meaning its funnel and session analytics are designed to avoid capturing personally identifiable information.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Who founded Corbado?$q$, $q$Corbado was founded in 2022 by Vincent Delitz, who was later joined by former CHECK24 CTO Kostas Pyliouras and engineers Stefan Becker and Martin Kellner.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Enterprise Passkey Rollouts$q$, $q$Large consumer platforms use Corbado Connect to add passkey sign-up and sign-in to their apps with prebuilt SDKs and staged rollout controls.$q$, $q$Enterprise CIAM and product engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Diagnosing Passkey Adoption Problems$q$, $q$Companies that already built their own passkey flow use Corbado Observe to find and fix drop-off points in the login funnel.$q$, $q$Platform and identity engineering teams with existing WebAuthn implementations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Reducing Password-Related Support Costs$q$, $q$Organizations facing high volumes of password-reset tickets and credential-stuffing fraud adopt passkeys via Corbado to cut both support costs and account-takeover risk.$q$, $q$Fintech, e-commerce, and other high-traffic consumer platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Corbado Observe$q$, $q$Custom$q$, $q$Contact Sales$q$, NULL, $q$["Authentication process mining","Per-user debugging","Readiness insights","AI-assisted reporting","Zero-PII telemetry"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$Corbado Connect$q$, $q$Custom$q$, $q$Contact Sales$q$, NULL, $q$["Managed sign-up and sign-in journeys","SDKs and UI components","Rollout controls with safe fallbacks","Built-in passkey analytics","Implementation guidance"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Corbado is a passkey-focused authentication company founded in 2022 in Munich, Germany. It builds tooling that helps enterprises add FIDO2/WebAuthn passkey sign-in to their existing login flows, and it offers analytics that reveal where passkey adoption succeeds or fails across devices, browsers, and user segments.$q$, $q$The company operates two distinct products: Corbado Connect, a managed passkey layer with SDKs and rollout controls, and Corbado Observe, an observability layer for teams that already run their own passkey implementation. Both integrate with existing identity providers such as Okta, Auth0, and Amazon Cognito rather than replacing them.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Corbado Connect provides prebuilt SDKs and UI components for passkey sign-up and sign-in, gradual rollout controls with safe fallback to passwords or other methods, and built-in funnel analytics to track adoption in real time.$q$, $q$Corbado Observe adds authentication process mining and per-user session debugging to an existing login stack, helping teams pinpoint exactly where and why passkey authentication attempts fail, without collecting personally identifiable data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Corbado does not publish self-serve pricing. Both Corbado Connect and Corbado Observe are sold through a custom, sales-assisted process typical of enterprise CIAM tooling, with pricing scaled to factors such as monthly active users and the identity providers being integrated.$q$, $q$Prospective customers request a demo or quote directly from Corbado rather than signing up for a fixed monthly plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('62db571f-582a-43e0-9f5f-3cf4413ae59a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Symfony Bundle Architecture$q$, $q$CoreShop is composed of decoupled, reusable Symfony bundles that can be adopted individually or as a full commerce suite.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Pimcore PIM/DAM Integration$q$, $q$Commerce functionality is built directly on top of Pimcore's product information and digital asset management data model, avoiding data duplication between systems.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Headless Commerce via DataHub$q$, $q$Pimcore DataHub exposes product and order data through APIs consumable by React, Next.js, and other modern frontend frameworks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Payment Gateway Abstraction$q$, $q$Payments integrate through the Payum abstraction library, supporting multiple payment gateways through a common interface.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Shipping and Tax Rules$q$, $q$Configurable shipping rules and tax zones support multi-region and multi-currency storefronts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Voucher and Discount Engine$q$, $q$Built-in support for vouchers and promotional discounts at the order and cart level.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Pimcore Studio Admin UI$q$, $q$The 2026.x release line ships a rewritten React/TypeScript admin interface, with each CoreShop bundle contributing its own Studio plugin via module federation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Multi-Store and Multi-Language Support$q$, $q$Inherits Pimcore's multi-language, multi-channel data model to support catalogs sold across multiple stores and locales.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Deep, native integration with Pimcore's PIM and DAM capabilities that most standalone commerce platforms can't match$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Modular Symfony bundle architecture allows teams to use only the components they need$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Supports headless/API-first commerce for modern frontend stacks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Strong fit for complex, high-SKU catalogs with rich structured product data$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Requires Symfony and Pimcore expertise, giving it a steeper learning curve than turnkey commerce platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Smaller community and ecosystem than Magento, Shopify, or WooCommerce$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$The April 2025 shift to an open-core license means some enterprise use cases now require a paid Commercial License$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Documentation is spread across multiple version branches, which can make it harder to find current guidance$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Is CoreShop free?$q$, $q$CoreShop's core is source-available and free to self-host. Since April 2025 it operates under an open-core license, and certain enterprise use cases require a paid CoreShop Commercial License.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$What's the difference between CoreShop and Pimcore?$q$, $q$Pimcore is a broader data platform for product information, digital assets, and content management. CoreShop is the e-commerce layer built on top of Pimcore, adding order management, payments, shipping, and tax functionality.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Does CoreShop support headless commerce?$q$, $q$Yes. CoreShop supports API-first, headless commerce through Pimcore DataHub, allowing frontends built with frameworks like React or Next.js to consume commerce data directly.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$What changed with CoreShop's 2025 license update?$q$, $q$Following a license change at Pimcore in April 2025, CoreShop moved to an open-core licensing model. Source code remains viewable, but certain deployments now require a separate Commercial License purchased through the Pimcore Store.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$What skills do I need to run CoreShop?$q$, $q$CoreShop implementations typically require PHP and Symfony development experience, plus familiarity with Pimcore's data model, making it best suited to development teams or Pimcore-certified agencies.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Can I use CoreShop without Pimcore?$q$, $q$CoreShop's components are built as Symfony bundles and are designed to work with Pimcore's data layer; running CoreShop's commerce features without Pimcore is not the framework's intended use case.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Unified PIM and Commerce$q$, $q$Organizations already using Pimcore for product data management extend it into full transactional e-commerce without maintaining a separate, disconnected shop platform.$q$, $q$Manufacturers, distributors, and B2B companies with complex product catalogs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Custom Symfony-Based Storefronts$q$, $q$Development agencies build bespoke commerce sites by selectively integrating CoreShop's Symfony bundles into custom applications.$q$, $q$Digital agencies and in-house PHP/Symfony development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Multi-Language, Multi-Store Catalogs$q$, $q$Businesses selling across multiple regions and languages use CoreShop's Pimcore-inherited multi-store data model to manage a single source of product truth.$q$, $q$Multi-brand and international retailers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Community (Open Core)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Source-available CoreShop bundles","Self-hosted deployment","Core commerce functionality (orders, payments, shipping, tax, vouchers)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$Commercial License$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Rights for enterprise/commercial use cases beyond open-core terms","Purchased via the Pimcore Store","Access to additional enterprise-oriented bundles"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CoreShop is an e-commerce framework that has been developed alongside the Pimcore PIM/DAM/CMS platform since 2012. It adds order management, payment, shipping, tax, and voucher functionality on top of Pimcore's product data and asset management capabilities.$q$, $q$Built as a set of Symfony bundles, CoreShop can be used as standalone components in a Symfony app, selectively integrated into an existing Pimcore installation, or adopted as a full commerce suite for a new build.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CoreShop supports headless, API-first commerce through Pimcore DataHub, allowing modern frontends built with React or Next.js to consume product and order data directly.$q$, $q$Core commerce functionality includes order management, payment gateway abstraction via the Payum library, configurable shipping rules, tax zones, multi-currency pricing, and a voucher and discount engine, all built around Pimcore's structured product catalog.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CoreShop's core is source-available and free to self-host. Following an April 2025 license change aligned with Pimcore's own licensing shift, CoreShop moved to an open-core model, with a separate CoreShop Commercial License required for certain enterprise use cases and available for purchase through the Pimcore Store.$q$, $q$There is no fixed SaaS subscription price; costs depend on whether a deployment stays within the free open-core terms or requires a commercial license, plus any Pimcore Enterprise licensing the underlying platform requires.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69b58e37-645a-40d2-a5a2-c859a6b2c481', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$eBPF Zero-Instrumentation Monitoring$q$, $q$Automatically collects metrics, logs, traces, and profiles at the kernel level without requiring code changes, SDKs, or manual instrumentation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Automatic Service Maps$q$, $q$Builds a real-time topology map of application services and their dependencies based on observed network traffic.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$SLO Tracking$q$, $q$Defines and tracks service-level objectives to monitor reliability against agreed targets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$AI-Powered Root Cause Analysis$q$, $q$Correlates signals across metrics, logs, traces, and profiles to help engineers move quickly from an anomaly to a likely cause.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Continuous Profiling$q$, $q$Captures ongoing performance profiles of running applications to support performance troubleshooting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Cloud Cost Monitoring$q$, $q$Tracks infrastructure cost alongside performance data to connect spend with resource usage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Smart Alerting$q$, $q$Sends alerts to Slack, PagerDuty, and Microsoft Teams based on anomaly detection and SLO breaches.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Deployment Tracking$q$, $q$Correlates new deployments with subsequent changes in performance or error rates.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$No code instrumentation required — eBPF collects telemetry automatically at the kernel level$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Generous, genuinely free-forever self-hosted Community Edition for development and smaller production clusters$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Predictable per-core pricing with no separate data-volume fees, unlike many usage-based observability vendors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Strong Kubernetes-native fit with automatic service mapping across polyglot service fleets$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Smaller integration ecosystem and community than established players like Datadog, New Relic, or Grafana$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$eBPF requires sufficient Linux kernel support and permissions, which can complicate deployment in some restricted environments$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Enterprise features such as 24/7 support and air-gapped installation are reserved for the higher-priced Premium tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Young, small company (founded 2021, reportedly under 10 employees) relative to legacy APM vendors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Is Coroot free?$q$, $q$Yes. Coroot's Community Edition is fully open source, self-hosted, and free to use indefinitely, including for production Kubernetes clusters.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$What license is Coroot released under?$q$, $q$Coroot is released under the Apache 2.0 open-source license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Does Coroot require code changes to install?$q$, $q$No. Coroot uses eBPF to observe applications at the kernel level, so it does not require adding tracing SDKs or instrumentation code to your services.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$What is eBPF and why does Coroot use it?$q$, $q$eBPF is a Linux kernel technology that allows safe, sandboxed programs to run inside the kernel to observe system and network behavior. Coroot uses it to automatically collect metrics, logs, traces, and profiles without manual instrumentation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Can Coroot replace a hand-assembled Prometheus/Grafana stack?$q$, $q$Coroot is designed to replace much of the manual setup involved in assembling Prometheus, Grafana, and tracing tools separately, by providing automatic collection and correlation out of the box.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Does Coroot support non-Kubernetes environments?$q$, $q$Coroot is primarily designed and marketed for Kubernetes environments, where it deploys as a node-level agent observing every container on a node.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Kubernetes Cluster Observability$q$, $q$SRE and platform teams deploy Coroot as a node-level agent to get automatic service maps, metrics, and root cause analysis across Kubernetes clusters.$q$, $q$SRE and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Cost-Predictable Observability$q$, $q$Teams facing unpredictable bills from usage-based SaaS observability vendors switch to Coroot's flat per-core pricing model with no data-volume fees.$q$, $q$Engineering teams with cost-sensitive infrastructure budgets$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Rapid Incident Root Cause Analysis$q$, $q$On-call engineers use Coroot's AI-powered root cause analysis to move from an alert to a likely explanation without manually correlating dashboards.$q$, $q$On-call engineers and incident responders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","eBPF-based monitoring","Service maps, metrics, logs, traces, and profiling","Full source code on GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Standard$q$, $q$$1 per CPU core/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Community Edition","SSO and RBAC","Volume discounts at scale","Business-hours support via email, chat, or ticket","14-day trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$Premium$q$, $q$Custom$q$, $q$Contact Sales$q$, NULL, $q$["Everything in Standard","24/7 support including phone support","Premium onboarding","Capacity planning","Air-gapped installation support","Team training included"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Coroot is an open-source observability platform founded in 2021 in Palo Alto, California, by Anton Petruhin, Nikolay Sivko, and Percona co-founder Peter Zaitsev. It uses eBPF, a Linux kernel technology, to automatically collect metrics, logs, traces, and continuous profiles from applications without requiring code instrumentation.$q$, $q$Coroot is released under the Apache 2.0 license with a free, self-hosted Community Edition, plus paid Standard and Premium tiers that add enterprise features like SSO, RBAC, and 24/7 support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$eBPF-based zero-instrumentation monitoring automatically builds a real-time service map and observes network and process behavior at the kernel level across every container on a node.$q$, $q$Additional capabilities include SLO tracking, AI-powered root cause analysis, continuous profiling, cloud cost monitoring, deployment tracking, and alerting integrations with Slack, PagerDuty, and Microsoft Teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition is free and open source, suitable for self-hosted development and smaller production clusters. The Standard paid tier costs $1 per monitored CPU core per month with volume discounts and no data-volume-based fees, adding SSO, RBAC, and business-hours support.$q$, $q$A Premium tier with 24/7 support, phone support, capacity planning, air-gapped installation, and team training is available through direct sales contact, and a 14-day trial is offered for paid tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('883b2808-6d12-4830-b483-eca7281f59f1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Service Catalog$q$, $q$A centralized, auto-populated catalog of services, APIs, and infrastructure resources pulled from GitHub, Kubernetes, AWS, and CI/CD tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Scorecards$q$, $q$Configurable engineering-standards tracking that scores every service against criteria like test coverage, security patching, and documentation completeness.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Ownership and On-Call Mapping$q$, $q$Links each service to its owning team and on-call schedule, often synced from tools like PagerDuty.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Self-Service Actions and Templates$q$, $q$Lets developers scaffold new services according to organizational best practices without manual setup.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Engineering Intelligence and Analytics$q$, $q$Dashboards give engineering leadership visibility into service health and maturity across the portfolio.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Broad Integration Ecosystem$q$, $q$Connects with GitHub, Kubernetes, PagerDuty, AWS, and other common engineering tools to keep catalog data current.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Custom Workflows$q$, $q$Supports configurable workflows for governance processes like service onboarding and deprecation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Enterprise Access Controls$q$, $q$SSO and role-based access controls are available on higher-tier plans for larger organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Purpose-built for tracking service ownership and engineering standards at scale, not just documentation$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Well-capitalized (roughly $198M raised) with a large enterprise customer base signaling product stability$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Scorecards provide a measurable way to drive adoption of engineering best practices across teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Broad integration ecosystem connects with common engineering and on-call tooling$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Detailed pricing beyond the free tier is not fully public, requiring sales conversations for most plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Per-developer pricing can become expensive for large engineering organizations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Overkill for small teams or organizations running only a handful of services$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Name collision with the unrelated open-source Cortex project for Prometheus long-term storage can cause search and vendor confusion$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$What is Cortex used for?$q$, $q$Cortex is used as an internal developer portal that centralizes service ownership, documentation, and engineering standards tracking for organizations managing microservices.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Is there a free tier?$q$, $q$Yes. Cortex offers a free tier supporting up to 20 services with basic service catalog functionality.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$How is Cortex priced?$q$, $q$Cortex uses a freemium, per-developer subscription model. A Team plan is reported to start around $25 per developer per month, with custom Enterprise pricing for larger organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Is Cortex the same as the open-source Cortex project for Prometheus?$q$, $q$No. cortex.io is a commercial internal developer portal company, entirely separate from the CNCF's open-source Cortex project, which provides long-term storage for Prometheus metrics.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Who founded Cortex?$q$, $q$Cortex was founded in 2019 by Anish Dhar, Ganesh Datta, and Nikhil Unni, and is headquartered in San Francisco, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$What integrations does Cortex support?$q$, $q$Cortex integrates with tools including GitHub, Kubernetes, AWS, CI/CD pipelines, and on-call platforms like PagerDuty to keep its service catalog current.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Microservice Ownership Tracking$q$, $q$Platform engineering teams use Cortex's service catalog to maintain a clear, up-to-date record of who owns each service across a large microservices fleet.$q$, $q$Platform engineering and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Engineering Standards Enforcement$q$, $q$Engineering leadership uses scorecards to track and drive adoption of standards like test coverage, security patching, and documentation across every team.$q$, $q$Engineering leadership and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Developer Onboarding$q$, $q$New engineers use the service catalog to quickly understand system architecture, ownership, and documentation without relying on tribal knowledge.$q$, $q$Engineers joining teams with complex service architectures$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 20 services","Basic service catalog functionality"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Team$q$, $q$From $25/developer/month$q$, $q$Monthly or Annual$q$, NULL, $q$["Unlimited services","Scorecards","Advanced integrations","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$Enterprise$q$, $q$Custom$q$, $q$Contact Sales$q$, NULL, $q$["SSO","Advanced security controls","Custom SLAs","Dedicated customer success management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cortex (cortex.io) is a San Francisco-based internal developer portal founded in 2019 by Anish Dhar, Ganesh Datta, and Nikhil Unni. It centralizes service ownership, documentation, and engineering standards for organizations running complex microservices architectures.$q$, $q$This company is distinct from the unrelated open-source Cortex project maintained by the Cloud Native Computing Foundation, which provides long-term storage for Prometheus metrics. The two products share a name but serve entirely different purposes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of Cortex is a service catalog that ingests metadata from GitHub, Kubernetes, AWS, CI/CD pipelines, and on-call tools to give a unified view of every service, its owner, and its operational status.$q$, $q$Scorecards let platform teams define and automatically track engineering standards, such as test coverage, on-call readiness, or documentation completeness, across every service in the catalog, alongside self-service scaffolding templates and engineering analytics dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cortex offers a free tier for up to 20 services with basic catalog functionality. A Team plan is reported to start around $25 per developer per month with unlimited services, scorecards, and advanced integrations.$q$, $q$Enterprise pricing is custom and negotiated directly with Cortex's sales team, adding SSO, advanced security controls, custom SLAs, and dedicated customer success management.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3dc31633-727a-4c74-8a39-811e3fd310a2', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Low-Code Application Builder$q$, $q$A drag-and-drop interface for building record-based, structured data applications without extensive custom coding.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Built-In CRM Module$q$, $q$Corteza CRM ships as a ready-made application with lead, account, and deal tracking, lead scoring, and sales forecasting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Enterprise Messaging$q$, $q$Corteza Messaging provides Slack-like secure team communication built directly into the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Automation Module$q$, $q$A workflow automation engine can trigger actions like lead assignment or notifications based on defined business rules.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$REST API and Webhooks$q$, $q$Exposes a REST API and webhook support for integrating external systems and building custom automations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Go Backend, Vue.js Frontend$q$, $q$Built on a performant Go backend with a Vue.js frontend, deployable via Docker or Kubernetes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Apache 2.0 Open Source Licensing$q$, $q$Fully open-source code with no licensing fees, reviewable and modifiable by anyone.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Unified Workspace$q$, $q$Combines low-code apps, CRM, and messaging into a single connected workspace comparable to a self-hosted Google Workspace for business data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Fully open source under Apache 2.0 with no per-user licensing fees, unlike Salesforce or other commercial CRM/low-code platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Combines low-code app building, CRM, and enterprise messaging in a single self-hosted platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Backed by Planet Crust for optional paid support, custom development, and managed hosting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Self-hosting gives organizations full control over data residency and governance$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Smaller community, ecosystem, and third-party integration marketplace than Salesforce or well-funded commercial competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Self-hosting requires in-house or contracted DevOps capability (Docker/Kubernetes familiarity)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$UI polish and out-of-the-box templates can lag well-funded commercial low-code vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Fewer prebuilt native integrations compared to mainstream SaaS CRM and low-code platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Is Corteza really free?$q$, $q$Yes. Corteza is 100% open source under the Apache 2.0 license and can be self-hosted with no licensing fees. Optional paid support and managed hosting are available from Planet Crust.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$What license does Corteza use?$q$, $q$Corteza is released under the Apache 2.0 open-source license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Who maintains Corteza?$q$, $q$Corteza is developed and maintained by Planet Crust, a company founded in 2019 and headquartered in Cork, Ireland.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Can Corteza replace Salesforce?$q$, $q$Corteza is explicitly positioned as an open-source Salesforce alternative, with its Low Code, CRM, and Messaging components mapped against Salesforce's Lightning Platform, Sales Cloud, and Chatter.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$What's the difference between Corteza and Corteza CRM?$q$, $q$Corteza is the overall open-source low-code platform, including the application builder and messaging tools. Corteza CRM is specifically the CRM application built on top of that platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Does Corteza offer cloud hosting?$q$, $q$Corteza is primarily distributed for self-hosting via Docker or Kubernetes; Planet Crust offers managed hosting and support as a paid service for organizations that prefer not to self-host.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Self-Hosted Salesforce Alternative$q$, $q$Organizations wanting to avoid Salesforce's per-seat licensing costs and data lock-in deploy Corteza as a fully self-hosted, open-source alternative.$q$, $q$Cost-sensitive organizations and those with data-residency requirements$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Custom Record-Based Business Applications$q$, $q$Developers use Corteza's low-code builder to create custom internal applications for case management, project tracking, or other structured workflows.$q$, $q$Internal development teams and system integrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Unified CRM and Team Communication$q$, $q$Teams combine Corteza CRM with Corteza Messaging to manage sales pipelines and internal communication within a single connected platform.$q$, $q$Sales and operations teams at small and mid-sized organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under Apache 2.0","Low Code application builder","Corteza CRM and Messaging modules","REST API and webhook support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$Planet Crust Support and Hosting$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Paid support and consulting","Custom development services","Managed hosting option"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Corteza is a 100% open-source, Apache 2.0-licensed low-code platform developed by Planet Crust, founded in 2019 and headquartered in Cork, Ireland. It combines a low-code application builder, a CRM module, and an enterprise messaging tool in one self-hosted codebase.$q$, $q$Corteza is explicitly positioned as a free, open-source alternative to Salesforce, with its components mapped against Salesforce's Lightning Platform, Sales Cloud, and Chatter respectively.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Corteza Low Code provides a drag-and-drop builder for record-based business applications, backed by a Go-based backend and Vue.js frontend, with a REST API and webhook support for integrations.$q$, $q$Corteza CRM and Corteza Messaging ship as ready-made applications on top of the low-code layer, giving organizations lead/account tracking, automation, and Slack-like team messaging out of the box.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Corteza itself carries no licensing fees; it is free to download, self-host, and modify under the Apache 2.0 license, with cost limited to an organization's own infrastructure and DevOps effort.$q$, $q$Planet Crust, the company behind Corteza, offers optional paid support, custom development, and managed hosting for organizations that don't want to run the platform entirely in-house.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('925db15a-65f7-4d4f-bb9d-cd05222b869f', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Lead and Account Management$q$, $q$Provides a 360-degree view of leads and accounts with contact management and deal tracking.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Deal and Opportunity Tracking$q$, $q$Tracks deals through the sales pipeline alongside communication history and task management.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Lead Scoring and Sales Forecasting$q$, $q$Helps prioritize prospects with lead scoring and projects pipeline outcomes with sales forecasting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Built-In Automation Module$q$, $q$Automates CRM processes such as lead ranking, contact assignment, and triggered follow-up communications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Analytics and Reporting$q$, $q$Real-time graphs and metrics on pipeline health support data-driven sales decisions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Low-Code Customization$q$, $q$Fields, forms, and workflows can be customized using Corteza's underlying low-code platform rather than a fixed schema.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$REST API and Webhooks$q$, $q$Exposes the same REST API and webhook support as the broader Corteza platform for integrating external tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Self-Hosted Deployment$q$, $q$Deployable via Docker or Kubernetes, keeping customer and sales data entirely within the organization's own infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Free and open source with no per-seat licensing fees, unlike Salesforce, HubSpot, or Zoho CRM$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Fully customizable data model, fields, and workflows via the underlying Corteza low-code platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Includes built-in sales automation, lead scoring, and forecasting out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Self-hosting keeps customer and sales data entirely within the organization's own infrastructure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Requires self-hosting and DevOps capability, unlike turnkey SaaS CRM products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Smaller feature depth and third-party marketplace than dedicated commercial CRMs like HubSpot or Salesforce$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Fewer native integrations with popular marketing and support tools out of the box$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Smaller community and documentation base than mainstream CRM platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Is Corteza CRM free?$q$, $q$Yes. Corteza CRM is free and open source under the Apache 2.0 license, with cost limited to self-hosting infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$How is Corteza CRM different from the full Corteza platform?$q$, $q$Corteza is the overall open-source low-code platform, including a general application builder and messaging tools. Corteza CRM is specifically the ready-made CRM application built on top of that platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Can I customize Corteza CRM's fields and workflows?$q$, $q$Yes. Because Corteza CRM is built on Corteza's low-code engine, its data model, fields, forms, and workflows can be customized without a separate development framework.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Does Corteza CRM include sales automation?$q$, $q$Yes. Corteza CRM includes a built-in automation module for tasks like lead ranking, contact assignment, and triggered follow-up communications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$What license governs Corteza CRM?$q$, $q$Corteza CRM is released under the Apache 2.0 open-source license, the same license used for the broader Corteza platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Is hosting available if I don't want to self-host?$q$, $q$Planet Crust, the company behind Corteza, offers optional paid managed hosting and support for organizations that prefer not to self-host.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Free Self-Hosted CRM$q$, $q$Small and mid-sized businesses adopt Corteza CRM to get full CRM functionality without recurring per-seat SaaS fees.$q$, $q$Cost-conscious small and mid-sized sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Customizable Sales Pipeline Management$q$, $q$Organizations with non-standard sales processes use Corteza CRM's low-code customization to tailor fields and workflows to their exact process.$q$, $q$Sales operations teams with specialized pipeline requirements$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Salesforce Replacement$q$, $q$Organizations looking to move off Salesforce for cost or data-control reasons adopt Corteza CRM as an open-source, self-hosted alternative.$q$, $q$Organizations seeking to reduce CRM licensing costs or avoid vendor lock-in$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full CRM source code under Apache 2.0","Lead, account, and deal tracking","Built-in automation module","REST API and webhook support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Corteza CRM is the customer relationship management application built on the Corteza open-source low-code platform, maintained by Planet Crust (founded 2019, headquartered in Cork, Ireland). It is free, self-hosted, and licensed under Apache 2.0.$q$, $q$It provides lead, account, and deal tracking comparable in scope to Salesforce Sales Cloud, but as open-source software rather than a paid SaaS subscription.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core CRM functionality includes contact management, lead and deal tracking, communication history, task and calendar management, lead scoring, sales forecasting, and real-time reporting dashboards.$q$, $q$A built-in automation module lets teams automate processes such as lead ranking, contact assignment, and follow-up communications, and the entire CRM can be customized using Corteza's underlying low-code tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Corteza CRM has no licensing fees; it is free to self-host under the Apache 2.0 license, with cost limited to infrastructure and DevOps effort.$q$, $q$Planet Crust offers optional paid support, implementation consulting, and managed hosting for organizations that prefer not to self-host.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('016aac11-14a9-4e56-958c-3b361e5b1ef4', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Integrated Trust and Business Accounting$q$, $q$A native general ledger and IOLTA-compliant trust accounting system built directly into the practice management platform, eliminating the need for a separate bookkeeping tool.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Three-Way Trust Reconciliation$q$, $q$Automatically reconciles the trust ledger, bank statement, and client ledger balances to help firms stay compliant with state bar trust accounting rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Conflict Checking$q$, $q$Flags potential conflicts of interest before a new matter is opened.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Matter Management with Custom Fields$q$, $q$Configurable matter templates and custom fields adapt the platform to different practice areas.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Matter Workflows and Status Automation$q$, $q$Elite-tier workflow automation with dependent task and event logic and matter budgets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Time and Expense Tracking$q$, $q$Tracks billable time and expenses directly tied to matters for accurate client billing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Online Payments$q$, $q$Accepts credit card, debit card, and eCheck payments through the CosmoLexPay add-on.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Document Management and Mobile App$q$, $q$Centralized document storage tied to matters, accessible from a native mobile app.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Fully integrated general ledger and trust accounting eliminates the need for a separate bookkeeping tool like QuickBooks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Built-in three-way trust reconciliation helps firms stay compliant with strict IOLTA/state bar rules$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$100% cloud-based with no local software installation required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$10-day free trial with full functionality available before subscribing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Core plan pricing (Standard/Elite tiers) is not fully published and can require checking current rates directly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$CRM and website-building functionality are priced as separate add-ons rather than included in the base plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Smaller ecosystem of third-party integrations than category leader Clio$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Trial is limited to 10 days and restricts some features like bank feed connections$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$What is CosmoLex used for?$q$, $q$CosmoLex is used by law firms for practice management, combining case/matter management, trust and business accounting, billing, time tracking, and document management in one cloud-based platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Does CosmoLex include trust accounting?$q$, $q$Yes. CosmoLex has built-in IOLTA-compliant trust accounting with three-way reconciliation between the trust ledger, bank statement, and client ledger balances.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$How much does CosmoLex cost?$q$, $q$CosmoLex starts around $89 per user per month when billed annually (or about $99 per user per month billed monthly), with Elite and Elite plus Website tiers priced higher and add-ons like CRM and Websites priced separately.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Is there a free trial?$q$, $q$Yes. CosmoLex offers a 10-day free trial with full functionality, though some features such as bank feed connections are limited during the trial.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Who owns CosmoLex?$q$, $q$CosmoLex was acquired by Tabs3 Software in 2018 and now operates as part of ProfitSolv, a portfolio of software solutions for professional services firms headquartered in Knoxville, Tennessee.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$How is CosmoLex different from Clio?$q$, $q$Unlike Clio, which typically integrates with an external accounting tool like QuickBooks, CosmoLex includes a native general ledger and trust accounting system built directly into the practice management platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Trust Accounting Compliance$q$, $q$Law firms use CosmoLex's built-in trust accounting to stay compliant with state bar IOLTA rules without a separate bookkeeping system.$q$, $q$Solo practitioners and small to mid-sized law firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$All-in-One Practice Management$q$, $q$Firms consolidate matter management, billing, time tracking, and accounting into a single subscription instead of integrating multiple tools.$q$, $q$Small and mid-sized law firms without dedicated IT or accounting staff$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Client Billing and Payments$q$, $q$Firms use CosmoLex's time tracking and CosmoLexPay integration to bill clients accurately and accept online payments.$q$, $q$Billable-hours-based legal practices$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Standard$q$, $q$From $89/user/month (annual) / $99/user/month (monthly)$q$, $q$Monthly or Annual$q$, NULL, $q$["Conflict check","Calendaring and task management","Matter custom fields and templates","Mobile app","Document management","Time and expense tracking","Online payments","Trust and business accounting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Elite$q$, $q$Custom (higher than Standard)$q$, $q$Monthly or Annual$q$, NULL, $q$["Everything in Standard","Matter status board","Matter workflows with status automation","Dependent task and event logic","Matter budgets"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$Elite + Website$q$, $q$Custom (higher than Elite)$q$, $q$Monthly or Annual$q$, NULL, $q$["Everything in Elite","CosmoLex Website"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$CosmoLex CRM (Add-on)$q$, $q$$147/month (annual) / $177/month (monthly)$q$, $q$Monthly or Annual$q$, NULL, $q$["CRM for up to 3 users","Lead and client intake tracking"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CosmoLex is cloud-based legal practice management software founded in 2013 by Rakesh Kabra, built around fully integrated trust and business accounting rather than requiring a separate bookkeeping tool. It was acquired by Tabs3 Software in 2018 and now operates as part of ProfitSolv, headquartered in Knoxville, Tennessee.$q$, $q$The platform combines matter management, billing, time tracking, document management, and calendaring with a native general ledger and IOLTA-compliant trust accounting in a single web-based application.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CosmoLex's trust accounting module enforces state bar compliance requirements including three-way reconciliation between the trust ledger, bank statement, and client ledger balances, reducing the risk of accidental non-compliance with client-fund handling rules.$q$, $q$Additional features include conflict-of-interest checking, matter status boards and workflow automation, customizable data views, a mobile app, document management, and integrated online payment processing through CosmoLexPay.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CosmoLex is priced per user per month across Standard, Elite, and Elite plus Website tiers, starting around $89 per user per month billed annually (or roughly $99 monthly billed month-to-month).$q$, $q$Add-ons include CosmoLex CRM at around $147/month annually for up to three users and CosmoLex Websites at around $149/month annually, with a 10-day free trial available for the core platform.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cee2123f-c1f7-4345-90bb-fd1586f42fd7', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Template-Based Editing$q$, $q$Turns any existing HTML/CSS template into a CMS-managed site by inserting special tags directly into the markup, without requiring a rebuild.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Editable Regions$q$, $q$Designated sections of a template become editable through the admin panel, letting non-technical editors update content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Cloned Pages$q$, $q$A single template can generate repeated content structures such as blogs, portfolios, galleries, or event listings, each holding independent content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Comments and Moderation$q$, $q$Built-in visitor commenting with editor moderation before publishing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$SEO-Friendly Virtual Folders$q$, $q$Cloned pages can be organized into nestable virtual folders whose names appear directly in the URL.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Custom Templating System$q$, $q$Supports loops, conditionals, and custom tags for building complex page layouts without writing PHP.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$MySQL-Backed Database$q$, $q$Uses a traditional MySQL database, combining flat-template flexibility with structured content querying.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Open-Source Licensing$q$, $q$Released under the Common Public Attribution License 1.0, permitting free commercial use with source attribution.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Free and open source, with the entire codebase available for self-hosting and modification$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Lets designers reuse existing HTML/CSS templates directly instead of learning a new theming system$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Lightweight and simple compared to full-featured CMS platforms like WordPress or Drupal$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Built-in SEO-friendly URL structuring through nestable virtual folders$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Smaller plugin and theme ecosystem than WordPress, since it lacks a large third-party marketplace$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Free license requires visible attribution in the source code unless a commercial license is purchased$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Best suited to small-to-medium sites rather than complex enterprise or e-commerce deployments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Requires a MySQL database and PHP hosting, unlike pure flat-file CMS alternatives$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Is CouchCMS free?$q$, $q$Yes. CouchCMS is free and open source under the Common Public Attribution License 1.0, which permits commercial use but requires attribution in the source code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$What license does CouchCMS use?$q$, $q$CouchCMS is released under the Common Public Attribution License 1.0 (CPAL). A separate paid Commercial License is available for removing attribution and rebranding the admin panel.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Do I need to learn PHP to use CouchCMS?$q$, $q$No. CouchCMS is designed for web designers who know HTML and CSS; content is made editable by inserting special tags into an existing template rather than writing PHP code.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$How is CouchCMS different from WordPress?$q$, $q$CouchCMS lets designers start from an already-built HTML/CSS template and add editable regions directly, whereas WordPress requires building a theme around its own templating and plugin system. CouchCMS is generally lighter-weight and has a smaller ecosystem than WordPress.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Does CouchCMS support blogs and galleries?$q$, $q$Yes, through its cloned pages feature, which lets a single template generate repeated content structures such as blog posts, portfolio items, and image galleries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Does CouchCMS require a database?$q$, $q$Yes. CouchCMS uses a MySQL database alongside its template-based content model, combining flat-template flexibility with database-backed content storage.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Client Website Development$q$, $q$Freelance designers and small agencies use CouchCMS to deliver editable websites to clients without building a full custom theme system.$q$, $q$Web designers and small digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Simple Blogs and Portfolios$q$, $q$CouchCMS's cloned pages feature is used to power blogs, portfolios, and image galleries from a single reusable template.$q$, $q$Freelancers and small business website owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Lightweight CMS Alternative to WordPress$q$, $q$Developers who find WordPress's plugin and theming overhead unnecessary for small sites choose CouchCMS for its simplicity and direct HTML/CSS workflow.$q$, $q$Designers preferring hand-coded templates over page builders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full CMS source code","Self-hosted on PHP/MySQL","Editable regions and cloned pages","Templating system with loops and conditionals"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$Commercial License (CCCL)$q$, $q$Paid (one-time)$q$, $q$One-time$q$, NULL, $q$["Remove attribution link from front end","Rebrand admin panel logo and copyright","One month of premium support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CouchCMS is a lightweight, open-source PHP content management system created by developer Kamran Kashif, with copyright notices dating to 2009 and active maintenance continuing since. It is designed for web designers who want to make an existing HTML/CSS template editable without learning a separate templating language.$q$, $q$Rather than imposing a CMS-defined theme structure, CouchCMS lets designers insert special tags directly into an already-built template, turning designated regions into editable content managed through Couch's admin panel.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Editable regions let designated parts of an HTML template be edited through the admin panel, while cloned pages let a single template generate repeated content structures like blog posts, galleries, or event listings, each with its own content.$q$, $q$Built-in comment and moderation tools, a templating system with loops and conditionals, and nestable virtual folders for SEO-friendly URLs round out the core feature set.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CouchCMS is free and open source under the Common Public Attribution License 1.0, which permits commercial use but requires attribution to remain visible in the source code.$q$, $q$A separate Commercial License is available for designers who want to remove the visible attribution link and rebrand the admin panel, which also includes a period of premium support; there is only one version of the software, so the commercial license is a white-labeling and support add-on rather than a feature unlock.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ae627ac-41a3-4d2a-80ef-75696ca1cfb2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
